  "pageId": "sport-studies:2-5-1-why-performers-use-peds",
  "pageName": "2.5.1 Why Performers Use PEDs",
  "source": "match",
  "type": "mcq",
  "marks": 1,
  "question": "Which definition matches the key term “Sponsorship pressure”?",
